export const selectDashboardStats = (state: { admin: AdminState }) => {
  const { appointments } = state.admin;
  const today = appointments.filter((a) => a.date === ADMIN_TODAY_DATE);

  return {
    todayAppointments: today.length,
    pendingAppointments: appointments.filter((a) => a.status === "pending").length,
    weeklyCustomers: new Set(appointments.map((a) => a.customerId)).size,
    todayRevenue: today
      .filter((a) => a.status === "confirmed" || a.status === "completed")
      .reduce((sum, a) => sum + a.price, 0),
  };
};

export const selectBeautyProfileByCustomerId =
  (customerId: string) => (state: { admin: AdminState }) =>
    state.admin.beautyProfiles[customerId] ?? getDefaultBeautyProfile(customerId);

export const selectBeautyHistoryByCustomerId =
  (customerId: string) => (state: { admin: AdminState }) =>
    state.admin.beautyHistory
      .filter((e) => e.customerId === customerId)
      .sort((a, b) => b.createdAt.localeCompare(a.createdAt));

