"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  BookOpen,
  Plus,
  Edit2,
  Trash2,
  ChevronDown,
  Calendar,
  User,
  FlaskConical,
  AlertTriangle,
  Clock,
} from "lucide-react";
import { cn } from "@/lib/cn";
import type { BeautyHistoryEntry, CustomerBeautyProfile } from "@/lib/data/types";
import type { Service, Staff } from "@/lib/data/types";
import BeautyProfileCard from "./BeautyProfileCard";
import BeautyHistoryModal, {
  type BeautyHistoryFormData,
} from "./BeautyHistoryModal";

interface BeautyHistorySectionProps {
  customerId: string;
  profile: CustomerBeautyProfile;
  entries: BeautyHistoryEntry[];
  staffList: Staff[];
  serviceList: Service[];
  onSaveProfile: (profile: CustomerBeautyProfile) => void;
  onAddEntry: (data: BeautyHistoryFormData) => void;
  onUpdateEntry: (entry: BeautyHistoryEntry) => void;
  onRemoveEntry: (id: string) => void;
}

export default function BeautyHistorySection({
  customerId,
  profile,
  entries,
  staffList,
  serviceList,
  onSaveProfile,
  onAddEntry,
  onUpdateEntry,
  onRemoveEntry,
}: BeautyHistorySectionProps) {
  const [modalOpen, setModalOpen] = useState(false);
  const [editingEntry, setEditingEntry] = useState<BeautyHistoryEntry | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [expandedId, setExpandedId] = useState<string | null>(
    entries[0]?.id ?? null
  );

  const handleOpenAdd = () => {
    setEditingEntry(null);
    setModalOpen(true);
  };

  const handleOpenEdit = (entry: BeautyHistoryEntry) => {
    setEditingEntry(entry);
    setModalOpen(true);
  };

  const handleSave = async (data: BeautyHistoryFormData) => {
    setIsLoading(true);
    await new Promise((r) => setTimeout(r, 400));

    const staff = staffList.find((s) => s.id === data.staffId);
    const service = serviceList.find((s) => s.id === data.serviceId);

    if (editingEntry) {
      onUpdateEntry({
        ...editingEntry,
        ...data,
        staffName: staff?.name ?? editingEntry.staffName,
        serviceName: service?.name ?? editingEntry.serviceName,
      });
    } else {
      onAddEntry({
        ...data,
        staffName: staff?.name ?? "",
        serviceName: service?.name ?? "",
      } as BeautyHistoryFormData & { staffName: string; serviceName: string });
    }

    setIsLoading(false);
    setModalOpen(false);
    setEditingEntry(null);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("آیا از حذف این یادداشت کارنامه مطمئن هستید؟")) {
      onRemoveEntry(id);
      if (expandedId === id) setExpandedId(null);
    }
  };

  return (
    <div className="space-y-6">
      <BeautyProfileCard profile={profile} onSave={onSaveProfile} />

      <div className="rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 overflow-hidden">
        <div className="flex items-center justify-between p-5 border-b border-[#2A2A3A]">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#C9A96E]/20 to-[#C9A96E]/5 flex items-center justify-center">
              <BookOpen size={20} className="text-[#C9A96E]" />
            </div>
            <div>
              <h2 className="text-lg font-bold text-[#F5F0E8]">سابقه کارنامه زیبایی</h2>
              <p className="text-xs text-[#A09880]">
                {entries.length} یادداشت ثبت‌شده — فرمول‌ها، تکنیک‌ها و نتایج هر جلسه
              </p>
            </div>
          </div>
          <button
            onClick={handleOpenAdd}
            className="btn-gold px-4 py-2 text-sm font-bold flex items-center gap-2"
          >
            <Plus size={16} />
            یادداشت جدید
          </button>
        </div>

        <div className="p-4">
          {entries.length === 0 ? (
            <div className="py-12 text-center">
              <BookOpen size={48} className="mx-auto text-[#A09880]/50 mb-4" />
              <h3 className="text-lg font-bold text-[#F5F0E8] mb-2">
                هنوز یادداشتی ثبت نشده
              </h3>
              <p className="text-sm text-[#A09880] mb-6 max-w-md mx-auto">
                بعد از هر مراجعه، فرمول رنگ، تکنیک کار و ترجیحات مشتری را اینجا ثبت
                کنید تا دفعه بعد دقیقاً بدانید چه کاری انجام شده.
              </p>
              <button onClick={handleOpenAdd} className="btn-gold px-6 py-2.5 text-sm font-bold">
                ثبت اولین یادداشت
              </button>
            </div>
          ) : (
            <div className="space-y-3">
              {entries.map((entry, i) => (
                <HistoryEntryCard
                  key={entry.id}
                  entry={entry}
                  index={i}
                  isExpanded={expandedId === entry.id}
                  onToggle={() =>
                    setExpandedId(expandedId === entry.id ? null : entry.id)
                  }
                  onEdit={() => handleOpenEdit(entry)}
                  onDelete={() => handleDelete(entry.id)}
                />
              ))}
            </div>
          )}
        </div>
      </div>

      <BeautyHistoryModal
        isOpen={modalOpen}
        onClose={() => {
          setModalOpen(false);
          setEditingEntry(null);
        }}
        onSave={handleSave}
        initialData={editingEntry}
        customerId={customerId}
        staffList={staffList}
        serviceList={serviceList}
        isLoading={isLoading}
      />
    </div>
  );
}

function HistoryEntryCard({
  entry,
  index,
  isExpanded,
  onToggle,
  onEdit,
  onDelete,
}: {
  entry: BeautyHistoryEntry;
  index: number;
  isExpanded: boolean;
  onToggle: () => void;
  onEdit: () => void;
  onDelete: () => void;
}) {
  const hasSensitivity =
    entry.sensitivitiesNoted.trim() && entry.sensitivitiesNoted !== "—";

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.04 }}
      className="rounded-xl bg-white/5 border border-white/5 overflow-hidden"
    >
      <button
        onClick={onToggle}
        className="w-full flex items-center gap-4 p-4 text-right hover:bg-white/[0.04] transition-colors"
      >
        <div className="text-center min-w-[56px] shrink-0">
          <div className="text-xs text-[#C9A96E] font-medium">{entry.date}</div>
        </div>

        <div className="w-px h-10 bg-[#2A2A3A] shrink-0" />

        <div className="flex-1 min-w-0">
          <p className="font-medium text-[#F5F0E8] truncate">{entry.serviceName}</p>
          <p className="text-xs text-[#A09880]">{entry.staffName}</p>
        </div>

        {hasSensitivity && (
          <span className="hidden sm:flex items-center gap-1 px-2 py-1 rounded-lg bg-[#E05555]/10 text-[#E05555] text-xs shrink-0">
            <AlertTriangle size={12} />
            حساسیت
          </span>
        )}

        {entry.nextVisitRecommendation &&
          entry.nextVisitRecommendation !== "—" && (
            <span className="hidden md:flex items-center gap-1 px-2 py-1 rounded-lg bg-[#3B82F6]/10 text-[#3B82F6] text-xs shrink-0">
              <Clock size={12} />
              {entry.nextVisitRecommendation}
            </span>
          )}

        <ChevronDown
          size={18}
          className={cn(
            "text-[#A09880] shrink-0 transition-transform",
            isExpanded && "rotate-180"
          )}
        />
      </button>

      <AnimatePresence>
        {isExpanded && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            transition={{ duration: 0.2 }}
            className="overflow-hidden"
          >
            <div className="px-4 pb-4 pt-0 border-t border-[#2A2A3A]/50">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4">
                <DetailField
                  icon={Calendar}
                  label="تاریخ"
                  value={entry.date}
                />
                <DetailField icon={User} label="آرایشگر" value={entry.staffName} />
                {entry.formulasUsed && entry.formulasUsed !== "—" && (
                  <DetailField
                    icon={FlaskConical}
                    label="فرمول / مواد"
                    value={entry.formulasUsed}
                    className="sm:col-span-2"
                  />
                )}
                {entry.techniquesApplied && (
                  <DetailField
                    label="تکنیک"
                    value={entry.techniquesApplied}
                    className="sm:col-span-2"
                  />
                )}
                {entry.clientPreferences && (
                  <DetailField
                    label="ترجیحات جلسه"
                    value={entry.clientPreferences}
                    className="sm:col-span-2"
                  />
                )}
                {hasSensitivity && (
                  <DetailField
                    icon={AlertTriangle}
                    label="حساسیت"
                    value={entry.sensitivitiesNoted}
                    className="sm:col-span-2"
                    highlight
                  />
                )}
                {entry.resultNotes && (
                  <DetailField
                    label="نتیجه"
                    value={entry.resultNotes}
                    className="sm:col-span-2"
                  />
                )}
                {entry.nextVisitRecommendation &&
                  entry.nextVisitRecommendation !== "—" && (
                    <DetailField
                      icon={Clock}
                      label="مراجعه بعدی"
                      value={entry.nextVisitRecommendation}
                      className="sm:col-span-2"
                    />
                  )}
              </div>

              <div className="flex items-center gap-2 mt-4 pt-4 border-t border-[#2A2A3A]/50">
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onEdit();
                  }}
                  className="px-3 py-1.5 rounded-lg bg-white/5 text-sm text-[#A09880] hover:text-[#C9A96E] hover:bg-[#C9A96E]/10 transition-colors flex items-center gap-1"
                >
                  <Edit2 size={14} />
                  ویرایش
                </button>
                <button
                  onClick={(e) => {
                    e.stopPropagation();
                    onDelete();
                  }}
                  className="px-3 py-1.5 rounded-lg bg-white/5 text-sm text-[#A09880] hover:text-[#E05555] hover:bg-[#E05555]/10 transition-colors flex items-center gap-1"
                >
                  <Trash2 size={14} />
                  حذف
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </motion.div>
  );
}

function DetailField({
  icon: Icon,
  label,
  value,
  className,
  highlight,
}: {
  icon?: React.ComponentType<{ size?: number; className?: string }>;
  label: string;
