  const hasSensitivities = !!beautyProfile.sensitivities.trim();
  const historyCount = beautyHistory.length;

  const tabs: { id: Tab; label: string; badge?: number }[] = [
    { id: "upcoming", label: "نوبت‌های آینده" },
