                <motion.div
                  layoutId="activeTab"
                  className="absolute bottom-0 right-0 left-0 h-0.5 bg-[#C9A96E]"
                />
              )}
            </button>
          ))}
        </div>

        <div className="p-4">
          {activeTab === "beauty" ? (
            <BeautyHistorySection
              customerId={customerId}
              profile={beautyProfile}
              entries={beautyHistory}
              staffList={staffList}
              serviceList={serviceList}
              onSaveProfile={(profile) => dispatch(upsertBeautyProfile(profile))}
              onAddEntry={(data) => dispatch(addBeautyHistoryEntry(data))}
              onUpdateEntry={(entry) => dispatch(updateBeautyHistoryEntry(entry))}
              onRemoveEntry={(id) => dispatch(removeBeautyHistoryEntry(id))}
            />
          ) : appointments.length === 0 ? (
            <div className="py-12 text-center">
              <CalendarX size={48} className="mx-auto text-[#A09880] mb-4" />
              <h3 className="text-lg font-bold text-[#F5F0E8] mb-2">
                {activeTab === "upcoming"
                  ? "نوبت آینده‌ای ندارد"
                  : "سابقه‌ای وجود ندارد"}
              </h3>
              <p className="text-sm text-[#A09880] mb-6">
                {activeTab === "upcoming"
                  ? "برای این مشتری هنوز نوبتی ثبت نشده است"
                  : "این مشتری هنوز نوبتی نگرفته است"}
              </p>
              <button className="btn-gold px-6 py-2.5 text-sm font-bold">
                ثبت اولین نوبت
              </button>
            </div>
          ) : (
            <div className="space-y-3">
              {appointments.map((apt, i) => {
                const status = statusConfig[apt.status];
                return (
                  <motion.div
                    key={apt.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: i * 0.05 }}
                    className="flex items-center gap-4 p-4 rounded-xl bg-white/5 hover:bg-white/[0.08] transition-colors"
                  >
                    <div className="text-center min-w-[60px]">
                      <div className="flex items-center justify-center gap-1 text-sm text-[#C9A96E]">
                        <Calendar size={12} />
                        {apt.date.split("/").slice(1).join("/")}
                      </div>
                      <div className="flex items-center justify-center gap-1 text-xs text-[#A09880] mt-1">
                        <Clock size={10} />
                        {apt.time}
                      </div>
                    </div>

                    <div className="w-px h-10 bg-[#2A2A3A]" />

                    <div className="flex-1">
                      <p className="font-medium text-[#F5F0E8]">
                        {apt.serviceName}
                      </p>
                      <p className="text-xs text-[#A09880]">{apt.staffName}</p>
                    </div>

                    <span
                      className={cn(
                        "px-2.5 py-1 rounded-lg text-xs font-medium",
                        status.bg,
                        status.color
                      )}
                    >
                      {status.label}
                    </span>
                  </motion.div>
                );
              })}
            </div>
          )}
        </div>
      </motion.div>
    </div>
  );
}
